// Measures the installed bundle size of `import { GridLayout } from "@snapgridjs/react"`
// and writes the numbers to a generated module so the hero + docs read ONE source
// of truth (no hand-maintained figures to drift). Decomposes snapgrid vs dnd-kit
// by bundling twice — once with dnd-kit included, once with it external.
//
//   node apps/docs/scripts/measure-bundle.mjs
//
// Runs in `prebuild` (needs the workspace packages built + node_modules present).
// On any failure it leaves the committed bundle-size.ts untouched, so a measurement
// hiccup never breaks the build.
import { writeFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import { brotliCompressSync } from "node:zlib";
import esbuild from "esbuild";

const RESOLVE_DIR = fileURLToPath(new URL("..", import.meta.url)); // apps/docs
const OUT = fileURLToPath(new URL("../components/generated/bundle-size.ts", import.meta.url));
const ENTRY = `import { GridLayout } from "@snapgridjs/react"; if (GridLayout) globalThis.x = 1;`;

async function bundleBytes(external) {
  const result = await esbuild.build({
    stdin: { contents: ENTRY, resolveDir: RESOLVE_DIR, loader: "js" },
    bundle: true,
    minify: true,
    format: "esm",
    write: false,
    external,
    logLevel: "silent",
  });
  return result.outputFiles[0].contents;
}

const kb = (bytes) => Math.round(brotliCompressSync(bytes).length / 1024);

try {
  // Full install (React is a peer the host app already ships, so exclude it).
  const total = await bundleBytes(["react", "react-dom"]);
  // Same, but with dnd-kit external too → snapgrid's own code + its packing engine.
  const ownOnly = await bundleBytes(["react", "react-dom", "@dnd-kit/*"]);

  const totalKb = kb(total);
  const snapgridKb = kb(ownOnly);
  const dndkitKb = totalKb - snapgridKb;

  await writeFile(
    OUT,
    `// AUTO-GENERATED by scripts/measure-bundle.mjs — do not edit by hand.
// Regenerate with: pnpm --filter @snapgridjs/docs measure
// Minified + tree-shaken \`import { GridLayout }\`, brotli, React excluded.
export const BUNDLE_SIZE = {
  total: ${totalKb},
  snapgrid: ${snapgridKb},
  dndkit: ${dndkitKb},
  unit: "kB",
  compression: "brotli",
} as const;
`,
  );
  console.log(
    `measured bundle → ${OUT} (total ${totalKb}kB = snapgrid ${snapgridKb} + dnd-kit ${dndkitKb}, brotli)`,
  );
} catch (err) {
  console.warn(`measure-bundle: skipped (${err.message}); keeping committed bundle-size.ts`);
}
